require_once __DIR__ . '/auth/auth_check.php'; require_once __DIR__ . '/config/billing_helpers.php';
$bill = !empty($_GET['bill']) ? find_bill_by_token($_GET['bill']) : null;
$bills=$pdo->query("SELECT b.*, c.name client_name FROM bills b JOIN clients c ON c.id=b.client_id WHERE b.due_amount>0 ORDER BY b.id DESC")->fetchAll();
$pageTitle='Receive Payment'; $active='payments';
include __DIR__.'/includes/head.php'; include __DIR__.'/includes/sidebar.php'; include __DIR__.'/includes/topbar.php';
